    "init":function(cmp, event, helper) {
        let colJson = cmp.get('v.columnsJson');
        let columns = JSON.parse(colJson);


        let showActionColumn = cmp.get('v.showActionColumn');
        if (showActionColumn) {
            var actions = [
                { label: 'Delete', name: 'delete' }
            ];
            let actionCol = { type: 'action', typeAttributes: { rowActions: actions } };
            columns.push(actionCol);
        }

		columns = columns.filter(col => col.label !== 'Hidden'); 

        cmp.set('v.columns', columns);

        let data = [];
        let dataJson = cmp.get('v.dataJson');
        if (cmp.get('v.hideCheckboxColumn')) {

	        cmp.set('v.dataSelectedJson', dataJson);
        }

        if (dataJson == undefined) { 
            data = [];
        	cmp.set('v.data', data);
        }
        else {
            data = JSON.parse(dataJson);
        	cmp.set('v.data', data);
        }

		let col1OptionsJson = cmp.get('v.col1PicklistJson');
        if (col1OptionsJson == undefined) { 
			cmp.set('v.col1OptionsShow', false);
        }
        else {
        	let col1Options = JSON.parse(col1OptionsJson)


            cmp.set('v.col1Label', col1Options[0].optionsLabel);
        	cmp.set('v.col1Options', col1Options);
            cmp.set('v.col1OptionsShow', true);
        }

        let col2OptionsJson = cmp.get('v.col2PicklistJson');
        if (col2OptionsJson == undefined) { 
			cmp.set('v.col2OptionsShow', false);
        }
        else {
        	let col2Options = JSON.parse(col2OptionsJson)
        	cmp.set('v.col2Options', col2Options);
            cmp.set('v.col2OptionsShow', true);
        }

        let col3OptionsJson = cmp.get('v.col3PicklistJson');
        if (col3OptionsJson == undefined) { 
			cmp.set('v.col3OptionsShow', false);
        }
        else {
        	let col3Options = JSON.parse(col3OptionsJson)
        	cmp.set('v.col3Options', col3Options);
            cmp.set('v.col3OptionsShow', true);
        }

        let col4OptionsJson = cmp.get('v.col4PicklistJson');
        if (col4OptionsJson == undefined) { 
			cmp.set('v.col4OptionsShow', false);
        }
        else {
        	let col4Options = JSON.parse(col4OptionsJson)
        	cmp.set('v.col4Options', col4Options);
            cmp.set('v.col4OptionsShow', true);
        }

    },
    "handleSelect":function(cmp, event, helper) {
        var selectedRows = event.getParam('selectedRows');
        cmp.set('v.dataSelectedJson', JSON.stringify(selectedRows));        
    },
    "handleRowAction":function(cmp, event, helper) {
        var action = event.getParam('action');
        var row = event.getParam('row');

        switch (action.name) {
            case 'delete':
                helper.removeRow(cmp, row);
                let data = cmp.get('v.data');
        		cmp.set('v.dataSelectedJson', JSON.stringify(data));
                break;
        }
    },
    "handleRowAdd":function(cmp, event, helper) {
        let data = cmp.get('v.data');
        let colVal1 = cmp.get('v.col1Selected');
        let colVal2 = cmp.get('v.col2Selected');
        let colVal3 = cmp.get('v.col3Selected');
        let colVal4 = cmp.get('v.col4Selected');
        let col1OptionsShow = cmp.get('v.col1OptionsShow');
        let col2OptionsShow = cmp.get('v.col2OptionsShow');
        let col3OptionsShow = cmp.get('v.col3OptionsShow');
        let col4OptionsShow = cmp.get('v.col4OptionsShow');
        let addRow = {};
        if (colVal1 !== undefined && col1OptionsShow) {
            addRow.col1 = colVal1;

            if (colVal2 !== undefined && col2OptionsShow) {
            	addRow.col2 = colVal2;

                if (colVal3 !== undefined && col3OptionsShow) {
                	addRow.col3 = colVal3;

                    if (colVal4 !== undefined && col4OptionsShow) {
                        addRow.col4 = colVal4;

                    }
                    else {
                        if (col4OptionsShow) addRow = {};

            		}
                }
                else {
                    if (col3OptionsShow) addRow = {};

                }
            }
            else {
                if (col2OptionsShow) addRow = {};

        	}
        }




        cmp.set('v.data', data);
        cmp.set('v.dataSelectedJson', JSON.stringify(data)); 
        let validationResponse = helper.executeCodeblock(cmp.get('v.dataSelectedJson'), 1, cmp.get('v.validateCodeblock'));



        if(Object.keys(addRow).length > 0 && validationResponse.status) {
            data.push(addRow);
            cmp.set('v.data', data);
            cmp.set('v.dataSelectedJson', JSON.stringify(data)); 
            let calculatedValue = helper.executeCodeblock(cmp.get('v.dataSelectedJson'), 1, cmp.get('v.calculateCodeblock'));


			cmp.set('v.calculateValue', calculatedValue);


            cmp.set('v.col1Selected', undefined);
            cmp.set('v.col2Selected', undefined);
            cmp.set('v.col3Selected', undefined);
            cmp.set('v.col4Selected', undefined);
            cmp.set('v.col1Value', '');
            cmp.set('v.col2Value', '');
            cmp.set('v.col3Value', '');
            cmp.set('v.col4Value', '');    
            cmp.set('v.validationStatus', true);    
            cmp.set('v.validationMessage', '');    
        } 
        else {
            cmp.set('v.validationStatus', false);    
            if(validationResponse.status) {
                cmp.set('v.validationMessage', 'You need to select a value for all the fields');    
            }
            else {
                cmp.set('v.validationMessage', validationResponse.message);    
            }
        }
        if(data.length > 9) {
            cmp.set('v.col1OptionsShow', false);
            cmp.set('v.col2OptionsShow', false);
            alert('Limit of 10 containers per case reached');
        }        
    },
    "handleChangeCol1":function(cmp, event) {
        cmp.set('v.col1Selected', event.getParam('value'));
    },
    "handleChangeCol2":function(cmp, event) {
        cmp.set('v.col2Selected', event.getParam('value'));
    },
    "handleChangeCol3":function(cmp, event) {
        cmp.set('v.col3Selected', event.getParam('value'));
    },
    "handleChangeCol4":function(cmp, event) {
        cmp.set('v.col4Selected', event.getParam('value'));
    }
  },
  "helper":{
    "removeRow":function(cmp, row) {
        var rows = cmp.get('v.data');
        var rowIndex = rows.indexOf(row);
        rows.splice(rowIndex, 1);
        cmp.set('v.data', rows);

        cmp.set('v.dataSelectedJson', JSON.stringify(rows));
    },
    "executeCodeblock":function(param1, param2, codeblock) {
         var functionToExecute = new Function ('param1', 'param2', codeblock);
         return functionToExecute(param1, param2);
    }
  }
};
